import { Tasks } from 'wasp/client/crud'
import './Main.css'

export function MainPage() {
  const { data: tasks, isLoading, error } = Tasks.getAll.useQuery()
  const createTaskAction = Tasks.create.useAction()

  const handleSubmit = async (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault()
    const formData = new FormData(event.currentTarget)
    const description = formData.get('description') as string
    try {
      await createTaskAction({ description })
      event.currentTarget.reset()
    } catch (err: any) {
      window.alert('Error: ' + err.message)
    }
  }

  if (isLoading) return 'Loading...'
  if (error) return 'Error: ' + error.message

  return (
    <main className="container">
      <h2 className="title">Tasks</h2>

      <form onSubmit={handleSubmit}>
        <input name="description" placeholder="Task description" required />
        <button type="submit">Create Task</button>
      </form>

      <ul className="content">
        {tasks?.map((task) => (
          <li key={task.id}>
            {task.description} {task.isDone ? '(Done)' : ''}
          </li>
        ))}
      </ul>
    </main>
  )
}

app crudOverride {
  wasp: {
    version: "^0.21.1"
  },
  title: "crud-override",
  head: [
    "<link rel='icon' href='/favicon.ico' />",
  ]
}

route RootRoute { path: "/", to: MainPage }
page MainPage {
  component: import { MainPage } from "@src/MainPage"
}

crud Tasks {
  entity: Task,
  operations: {
    getAll: {
      isPublic: true
    },
    create: {
      overrideFn: import { create } from "@src/tasks"
    }
  }
}

import { type Tasks } from 'wasp/server/crud'

export const create: Tasks.CreateAction = async (args: any, context) => {
  return context.entities.Task.create({
    data: {
      ...args,
      description: `${args.description} [NEW]`,
    },
  })
}

